/*
 * reflow_oven.ino — Smart Reflow Oven Controller
 *
 * Elements:
 *   1. MAX6675 K-type Thermocouple — SPI D10, temp at 4 Hz
 *   2. SSR × 2                    — D5 (top), D6 (bottom), 1-s window PID
 *   3. Rotary Encoder KY-040      — profile select + start/abort
 *   4. SSD1306 OLED               — phase / temp / time / PID
 *   5. Arduino Nano               — reflow state machine + PID
 *
 * Lead-free profile (IPC J-STD-020 D):
 *   PREHEAT : ramp 25  → 150 °C  (~90 s)
 *   SOAK    : hold 150 °C        (60 s)
 *   RAMP    : ramp 150 → 250 °C  (~45 s)
 *   REFLOW  : hold 250 °C        (30 s)
 *   COOL    : heaters OFF, wait T < 100 °C
 */

#include <Wire.h>
#include <SPI.h>
#include <max6675.h>
#include <Adafruit_SSD1306.h>

// --- Pins ---
#define TC_CS      10
#define TC_CLK     13
#define TC_MISO    12
#define SSR_TOP     5
#define SSR_BOT     6
#define BUZZ_PIN    8
#define ENC_CLK     2
#define ENC_DT      4
#define ENC_SW      3

// --- PID ---
#define KP 0.8f
#define KI 0.05f
#define KD 3.0f
#define PERIOD_MS  250UL
#define WINDOW_MS 1000UL

// --- Reflow phases (lead-free) ---
struct Phase { const char* name; float target_c; uint32_t max_s; };
const Phase PROFILE[] = {
  { "PREHEAT",  150.0f,  90 },
  { "SOAK",     150.0f,  60 },
  { "RAMP",     250.0f,  60 },
  { "REFLOW",   250.0f,  35 },
  { "COOL",       0.0f, 120 }
};
const uint8_t N_PHASES = 5;

// --- Objects ---
MAX6675         tc(TC_CLK, TC_CS, TC_MISO);
Adafruit_SSD1306 oled(128, 64, &Wire, -1);

// --- State ---
float   actual_c    = 20.0f;
float   setpoint_c  = 25.0f;
float   pid_out     = 0.0f;
float   i_term      = 0.0f;
float   prev_err    = 0.0f;
bool    running     = false;
uint8_t phase_idx   = 0;
unsigned long phase_start = 0;

volatile int  enc_d = 0;
volatile bool enc_p = false;
void ICACHE_RAM_ATTR isr_clk() { enc_d += digitalRead(ENC_DT) ? -1 : 1; }
void ICACHE_RAM_ATTR isr_sw()  { enc_p = true; }

float run_pid(float sp, float pv, float dt) {
  float e = sp - pv;
  i_term  = constrain(i_term + KI * e * dt, 0.0f, 100.0f);
  float d = (e - prev_err) / dt;
  prev_err = e;
  return constrain(KP * e + i_term + KD * d, 0.0f, 100.0f);
}

void abort_cycle() {
  running = false; phase_idx = 0; pid_out = 0; i_term = 0; prev_err = 0;
  digitalWrite(SSR_TOP, LOW); digitalWrite(SSR_BOT, LOW);
  Serial.println(F("ABORTED"));
}

void draw_oled() {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  if (!running) {
    oled.setCursor(0, 0); oled.print("REFLOW OVEN READY");
    oled.setCursor(0,16); oled.print("Press ENC to start");
    oled.setCursor(0,32); oled.printf("T = %.1f C", actual_c);
  } else {
    uint32_t elapsed = (millis() - phase_start) / 1000;
    oled.setCursor(0, 0); oled.print(PROFILE[phase_idx].name);
    oled.setTextSize(2);
    oled.setCursor(0,12); oled.printf("%.0f/%.0f", actual_c, setpoint_c);
    oled.setTextSize(1);
    oled.setCursor(0,36); oled.printf("t=%lus  P=%.0f%%", elapsed, pid_out);
  }
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  pinMode(SSR_TOP, OUTPUT); digitalWrite(SSR_TOP, LOW);
  pinMode(SSR_BOT, OUTPUT); digitalWrite(SSR_BOT, LOW);
  pinMode(BUZZ_PIN, OUTPUT); digitalWrite(BUZZ_PIN, LOW);
  pinMode(ENC_CLK, INPUT_PULLUP); pinMode(ENC_DT, INPUT_PULLUP); pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), isr_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  isr_sw,  FALLING);

  delay(500);  // MAX6675 power-up
  Serial.println(F("Reflow oven ready."));
}

void loop() {
  static unsigned long last_pid  = 0;
  static unsigned long win_start = 0;

  unsigned long now = millis();

  // --- Encoder ---
  noInterrupts(); bool p = enc_p; enc_p = false; int d = enc_d; enc_d = 0; interrupts();
  if (p) {
    if (!running) { running = true; phase_idx = 0; phase_start = now; i_term = 0; prev_err = 0; }
    else          { abort_cycle(); }
  }

  // --- Phase management ---
  if (running && phase_idx < N_PHASES) {
    uint32_t elapsed = (now - phase_start) / 1000;
    if (phase_idx < N_PHASES - 1) {
      bool phase_done = (elapsed >= PROFILE[phase_idx].max_s) ||
                        (phase_idx == 0 && actual_c >= 150.0f) ||
                        (phase_idx == 2 && actual_c >= 245.0f) ||
                        (phase_idx == 3 && elapsed >= PROFILE[3].max_s);
      if (phase_done) { phase_idx++; phase_start = now; }
    } else {
      // COOL phase done
      if (actual_c < 100.0f || elapsed >= PROFILE[4].max_s) {
        abort_cycle();
        for (int i = 0; i < 3; i++) { digitalWrite(BUZZ_PIN,HIGH); delay(300); digitalWrite(BUZZ_PIN,LOW); delay(300); }
        Serial.println(F("REFLOW DONE"));
      }
    }
    setpoint_c = (phase_idx == N_PHASES - 1) ? actual_c * 0.8f : PROFILE[phase_idx].target_c;
  }

  // --- PID at 4 Hz ---
  if (now - last_pid >= PERIOD_MS) {
    float dt = (now - last_pid) / 1000.0f;
    last_pid = now;
    actual_c = tc.readCelsius();
    if (actual_c > 300.0f) { abort_cycle(); return; }  // safety
    if (running && phase_idx < N_PHASES - 1) pid_out = run_pid(setpoint_c, actual_c, dt);
    else                                     pid_out = 0.0f;
    draw_oled();
    Serial.printf("PH=%s T=%.1f SP=%.0f OUT=%.0f\n", PROFILE[phase_idx].name, actual_c, setpoint_c, pid_out);
  }

  // --- SSR window ---
  if (now - win_start >= WINDOW_MS) win_start = now;
  bool heat_on = running && phase_idx < N_PHASES - 1 &&
                 (now - win_start) < (unsigned long)(pid_out * WINDOW_MS / 100.0f);
  digitalWrite(SSR_TOP, heat_on ? HIGH : LOW);
  digitalWrite(SSR_BOT, heat_on ? HIGH : LOW);
}
